insert into public.articles (
insert into public.attractions (id, name, slug, english_name, description, address, district, latitude, longitude, opening_hours, ticket_price, transport_info, cover_image, gallery, category, tags, rating, is_featured, seo_title, seo_description) values
('40000000-0000-4000-8000-000000000001', '外灘', 'the-bund', 'The Bund', '上海最具代表性的黃浦江濱水景觀。', '上海市黃浦區中山東一路', '黃浦區', 31.2401, 121.4908, '全天開放', '免費', '地鐵 2 / 10 號線南京東路站步行約 10 分鐘', 'https://images.unsplash.com/photo-1538428494232-9c0d8a3ab403?auto=format&fit=crop&w=1200&q=80', array['https://images.unsplash.com/photo-1538428494232-9c0d8a3ab403?auto=format&fit=crop&w=1200&q=80'], '必去', array['夜景','免費','攝影'], 4.8, true, '上海外灘攻略：交通、夜景、拍照點', '外灘是上海必去景點，整理交通方式、夜景拍攝點、附近美食住宿與順遊路線。'),
('40000000-0000-4000-8000-000000000002', '東方明珠', 'oriental-pearl-tower', 'Oriental Pearl Tower', '陸家嘴地標觀景塔，可俯瞰黃浦江兩岸。', '上海市浦東新區世紀大道 1 號', '浦東新區', 31.2397, 121.4998, '09:00-21:00', '依官方票種為準', '地鐵 2 號線陸家嘴站步行約 5 分鐘', 'https://images.unsplash.com/photo-1538428494232-9c0d8a3ab403?auto=format&fit=crop&w=1200&q=80', '{}', '夜景', array['觀景台','親子','地標'], 4.5, true, '東方明珠攻略：門票、交通與觀景重點', '上海東方明珠旅遊攻略，含交通、門票、觀景角度與附近景點住宿推薦。'),
('40000000-0000-4000-8000-000000000003', '上海迪士尼', 'shanghai-disneyland', 'Shanghai Disneyland', '華語旅客親子自由行熱門主題樂園。', '上海市浦東新區川沙新鎮黃趙路 310 號', '浦東新區', 31.1440, 121.6570, '依官方營業時間為準', '依日期浮動', '地鐵 11 號線迪士尼站', 'https://images.unsplash.com/photo-1578662996442-48f60103fc96?auto=format&fit=crop&w=1200&q=80', '{}', '親子', array['迪士尼','門票','Klook'], 4.7, true, '上海迪士尼攻略：交通、門票與設施安排', '上海迪士尼一日遊景點頁，整理交通、票券、附近住宿與相關攻略文章。'),
('40000000-0000-4000-8000-000000000004', '豫園', 'yu-garden', 'Yu Garden', '明代江南園林與老城廂商圈。', '上海市黃浦區安仁街 218 號', '黃浦區', 31.2272, 121.4921, '09:00-16:30', '依季節票價為準', '地鐵 10 / 14 號線豫園站', 'https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&w=1200&q=80', '{}', '必去', array['園林','老街','小吃'], 4.4, false, '上海豫園攻略：門票、交通與城隍廟順遊', '豫園景點介紹，含交通、開放時間、票價、附近美食與上海老城廂路線。'),
('40000000-0000-4000-8000-000000000005', '南京路步行街', 'nanjing-road', 'Nanjing Road Pedestrian Street', '上海經典商業街，適合購物、散步並一路走到外灘。', '上海市黃浦區南京東路', '黃浦區', 31.2350, 121.4750, '全天開放', '免費', '地鐵人民廣場站或南京東路站', 'https://images.unsplash.com/photo-1523731407965-2430cd12f5e4?auto=format&fit=crop&w=1200&q=80', '{}', '購物', array['購物','免費','夜景'], 4.3, true, '南京路步行街攻略：購物、交通與外灘路線', '上海南京路步行街旅遊攻略，整理交通、購物動線與外灘順遊安排。')
insert into public.restaurants (id, name, slug, description, address, district, latitude, longitude, phone, opening_hours, average_price, cuisine_type, cover_image, gallery, menu_images, rating, is_featured, seo_title, seo_description) values
('50000000-0000-4000-8000-000000000001', '南翔饅頭店', 'nanxiang-mantou-dian', '上海小籠包代表老店，豫園周邊人氣極高。', '上海市黃浦區豫園路 85 號', '黃浦區', 31.2279, 121.4920, '+86 21 6355 4206', '09:00-20:00', 250, '小籠包', 'https://images.unsplash.com/photo-1563245372-f21724e3856d?auto=format&fit=crop&w=1200&q=80', '{}', '{}', 4.2, true, '南翔饅頭店：上海小籠包老店攻略', '南翔饅頭店餐廳介紹，含地址、交通、人均消費、附近景點住宿與美食攻略。'),
('50000000-0000-4000-8000-000000000002', '海底撈', 'haidilao-shanghai', '服務細緻的連鎖火鍋，適合多人與宵夜場。', '上海多分店', '黃浦區', 31.2350, 121.4750, '', '依分店公告', 650, '火鍋', 'https://images.unsplash.com/photo-1569718212165-3a8278d5f624?auto=format&fit=crop&w=1200&q=80', '{}', '{}', 4.5, true, '上海海底撈攻略：分店、排隊與點餐提醒', '上海海底撈餐廳資訊，適合火鍋、宵夜與多人用餐，整理預算與交通建議。'),
('50000000-0000-4000-8000-000000000003', '老吉士', 'old-jesse', '上海本幫菜名店，紅燒肉、蟹粉豆腐等菜色受歡迎。', '上海市徐匯區天平路 41 號', '徐匯區', 31.2070, 121.4430, '+86 21 6282 9260', '11:00-14:00, 17:00-22:00', 900, '本幫菜', 'https://images.unsplash.com/photo-1544025162-d76694265947?auto=format&fit=crop&w=1200&q=80', '{}', '{}', 4.4, true, '老吉士上海本幫菜攻略', '老吉士餐廳介紹，含本幫菜推薦、人均消費、地址與附近景點安排。'),
('50000000-0000-4000-8000-000000000004', '佳家湯包', 'jia-jia-tang-bao', '人民廣場周邊人氣湯包店，適合早餐或午餐。', '上海市黃浦區黃河路 90 號', '黃浦區', 31.2360, 121.4700, '', '07:30-20:00', 180, '小籠包', 'https://images.unsplash.com/photo-1563245372-f21724e3856d?auto=format&fit=crop&w=1200&q=80', '{}', '{}', 4.3, false, '佳家湯包攻略：人民廣場小籠包推薦', '佳家湯包餐廳資訊，整理地址、營業時間、人均消費與附近住宿景點。'),
('50000000-0000-4000-8000-000000000005', '光明邨大酒家', 'guangmingcun-restaurant', '上海老字號餐廳與熟食名店，鮮肉月餅與本幫菜都受歡迎。', '上海市黃浦區淮海中路 588 號', '黃浦區', 31.2210, 121.4680, '', '10:00-21:00', 350, '本幫菜', 'https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=1200&q=80', '{}', '{}', 4.1, true, '光明邨大酒家攻略：上海老字號美食', '光明邨大酒家介紹，含推薦菜、人均消費、地址與上海老字號美食路線。')
insert into public.hotels (id, name, slug, description, address, district, latitude, longitude, star_rating, price_range, cover_image, gallery, rating, agoda_url, booking_url, trip_url, is_featured, seo_title, seo_description) values
('60000000-0000-4000-8000-000000000001', '上海外灘 W 酒店', 'w-shanghai-the-bund', '北外灘設計型高端飯店，適合重視江景與潮流風格的旅客。', '上海市虹口區旅順路 66 號', '虹口區', 31.2507, 121.5006, 5, '高價位', 'https://images.unsplash.com/photo-1566073771259-6a8506099945?auto=format&fit=crop&w=1200&q=80', '{}', 4.7, 'https://www.agoda.com/search?city=3987', 'https://www.booking.com/searchresults.html?ss=Shanghai', 'https://www.trip.com/hotels/list?city=2', true, '上海外灘 W 酒店住宿攻略', '上海外灘 W 酒店介紹，含地點、房價區間、附近景點、美食與 Agoda Booking 預訂連結。'),
('60000000-0000-4000-8000-000000000002', '上海和平飯店', 'fairmont-peace-hotel', '外灘經典歷史飯店，適合想體驗老上海建築氛圍的旅客。', '上海市黃浦區南京東路 20 號', '黃浦區', 31.2390, 121.4905, 5, '高價位', 'https://images.unsplash.com/photo-1551882547-ff40c63fe5fa?auto=format&fit=crop&w=1200&q=80', '{}', 4.8, 'https://www.agoda.com/search?city=3987', 'https://www.booking.com/searchresults.html?ss=Shanghai', 'https://www.trip.com/hotels/list?city=2', true, '上海和平飯店：外灘歷史飯店住宿攻略', '上海和平飯店住宿介紹，整理外灘位置、星級、價格區間、附近景點與訂房連結。'),
('60000000-0000-4000-8000-000000000003', '上海浦東麗思卡爾頓', 'ritz-carlton-shanghai-pudong', '陸家嘴高樓景觀飯店，適合想看外灘夜景與高端住宿體驗的旅客。', '上海市浦東新區世紀大道 8 號', '浦東新區', 31.2368, 121.5019, 5, '高價位', 'https://images.unsplash.com/photo-1566073771259-6a8506099945?auto=format&fit=crop&w=1200&q=80', '{}', 4.8, 'https://www.agoda.com/search?city=3987', 'https://www.booking.com/searchresults.html?ss=Shanghai', 'https://www.trip.com/hotels/list?city=2', true, '上海浦東麗思卡爾頓住宿攻略', '上海浦東麗思卡爾頓飯店介紹，含陸家嘴位置、夜景、附近景點與訂房連結。'),
('60000000-0000-4000-8000-000000000004', '上海迪士尼樂園酒店', 'shanghai-disneyland-hotel', '迪士尼園區主題飯店，適合親子旅客與早入園行程。', '上海市浦東新區申迪西路 1009 號', '浦東新區', 31.1480, 121.6600, 5, '高價位', 'https://images.unsplash.com/photo-1578662996442-48f60103fc96?auto=format&fit=crop&w=1200&q=80', '{}', 4.6, 'https://www.agoda.com/search?city=3987', 'https://www.booking.com/searchresults.html?ss=Shanghai%20Disney', 'https://www.trip.com/hotels/list?city=2', true, '上海迪士尼樂園酒店住宿攻略', '上海迪士尼樂園酒店介紹，整理親子住宿、園區交通、房價區間與票券搭配。'),
('60000000-0000-4000-8000-000000000005', '上海南京路附近飯店', 'nanjing-road-nearby-hotel', '人民廣場與南京東路周邊的高便利住宿選擇，適合第一次上海自由行。', '上海市黃浦區南京路周邊', '黃浦區', 31.2350, 121.4760, 4, '中價位', 'https://images.unsplash.com/photo-1566073771259-6a8506099945?auto=format&fit=crop&w=1200&q=80', '{}', 4.3, 'https://www.agoda.com/search?city=3987', 'https://www.booking.com/searchresults.html?ss=Nanjing%20Road%20Shanghai', 'https://www.trip.com/hotels/list?city=2', true, '上海南京路附近飯店推薦', '南京路附近住宿推薦，適合上海第一次自由行，整理交通、價格區間與附近景點。')
